    private static readonly string LinePoints = BuildLine(new double[] { 72, 48, 62, 34, 54, 28, 46, 22, 40 });
    private static readonly string LineSecondaryPoints = BuildLine(new double[] { 55, 70, 58, 52, 68, 50, 64, 56, 66 });
