            var y = PlotTop + (pct[i] / 100.0) * PlotH;
            if (i > 0) sb.Append(' ');
            sb.Append(x.ToString("0.##", CultureInfo.InvariantCulture)).Append(',').Append(y.ToString("0.##", CultureInfo.InvariantCulture));
