    {
        var formatter = Unit is not null ? $"{{value}} {Unit}" : "{value}";

        var series = new EChartSeries
        {
            Type = "gauge",
            Min = Min,
            Max = Max,
            Pointer = new EChartPointer { Show = ShowPointer },
            Detail = new EChartSeriesDetail
            {
                FontSize = 24,
                Formatter = formatter
            },
