            }
            // Ensure we reach 1.0
            var maxThreshold = Ranges.Max(r => r.Threshold);
            if (maxThreshold < Max)
            {
                var lastColor = Ranges.OrderBy(r => r.Threshold).Last().Color;
                colorStops.Add(new object[] { 1.0, lastColor });
            }

