            {
                ["axisLine"] = System.Text.Json.JsonSerializer.Deserialize<System.Text.Json.JsonElement>(
                    System.Text.Json.JsonSerializer.Serialize(new
                    {
                        lineStyle = new { width = 15, color = colorStops }
                    }))
            };
        }

        if (ShowDataLabels)
            series.Label = new EChartLabel { Show = true, Position = LabelPosition, Formatter = LabelFormat };

